import java.util.Scanner;
import java.util.Arrays;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String input = scanner.nextLine();

        // Limiting the size of the buffer to prevent buffer overflow
        byte[] buffer = new byte[10];

        if (input.length() > buffer.length) {
            System.out.println("Input exceeds buffer size. Please enter a shorter name.");
            return;
        }

        Arrays.fill(buffer, (byte) 0); // Clearing the buffer

        // Copying input into the buffer
        System.arraycopy(input.getBytes(), 0, buffer, 0, input.length());

        System.out.println("Hello, " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
